import React, { useEffect, useState } from "react";
import axios from "axios";

const LabourDashboard = () => {
  const [jobs, setJobs] = useState([]);

  const load = async () => {
    const res = await axios.get("http://localhost:5000/api/jobs/all");
    setJobs(res.data);
  };

  const accept = async (id) => {
    await axios.put(`http://localhost:5000/api/jobs/accept/${id}`);
    load();
  };

  useEffect(() => {
    load();
  }, []);

  return (
    <div>

      <h2>Labour Dashboard</h2>

      <div style={styles.grid}>
        {jobs.map(j => (
          <div key={j._id} style={styles.card}>

            <h4>{j.title}</h4>
            <p>Status: {j.status}</p>

            <button style={styles.btn} onClick={() => accept(j._id)}>
              Accept Job
            </button>

          </div>
        ))}
      </div>

    </div>
  );
};

export default LabourDashboard;

const styles = {
  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
    gap: "10px"
  },

  card: {
    background: "#111a2e",
    padding: "15px",
    borderRadius: "12px"
  },

  btn: {
    marginTop: "10px",
    background: "#22c55e",
    border: "none",
    padding: "8px",
    borderRadius: "8px",
    color: "white",
    width: "100%"
  }
};
